use std::collections::HashMap;

#[derive(Debug, Clone)]
struct Payload {
    key: String,
    value: i32,
}

fn process_data_stream(mut cache: HashMap<String, i32>, inputs: Vec<Payload>) -> Result<i32, &'static str> {
    for payload in inputs.into_iter() {
        match payload.key.as_str() {
            "SET_VALUE" => {
                if cache.contains_key(&payload.key) {
                    return Err("Key already exists and cannot be overwritten.");
                }
                cache.insert(payload.key.clone(), payload.value);
            },
            "INCREMENT" => {
                if let Some(current_val) = cache.get(&payload.key) {
                    let new_val = current_val + 1;
                    cache.insert(payload.key.clone(), new_val);
                }
            },
            "GET_RESULT" => {
                return Ok(*cache.get("FINAL_KEY").unwrap_or(&0));
            },
            _ => {
                return Err("Unknown operation received.");
            }
        }
    }
    Ok(0)
}

