use std::collections::HashMap;

struct GameState {
    player_id: u32,
    position: (f32, f32),
}

trait GameEvent {
    fn process(&self, state: &mut GameState) -> Result<(), String>;
}

fn main() {
    let mut state = GameState { player_id: 1, position: (0.0, 0.0) };

    let events: Vec<Box<dyn GameEvent>> = vec![
        Box::new(PositionUpdate { id: 1, x: 10.0, y: 5.0 }),
        Box::new(CharacterAction { id: 2, action_name: "shotgun fired" }),
        Box::new(CharacterAction { id: 1, action_name: "jumped" }),
    ];

    for event in events {
        if let Err(e) = event.process(&mut state) {
            eprintln!("Failed to process event: {}", e);
        }
    }
}

use std::error::Error;
use std::fmt;

trait Authenticator {
    fn get_user_id(&self) -> String;
    fn verify_signature(&self, data: &[u8]) -> Result<(), Box<dyn Error>>;
}

struct WebAuthnToken { 
    user_object: String,
    key_data: Vec<u8>
}
impl Authenticator for WebAuthnToken {
    fn get_user_id(&self) -> String { self.user_object.clone() }
    fn verify_signature(&self, data: &[u8]) -> Result<(), Box<dyn Error>> {
        if data.is_empty() { 
            return Err(Box::new(std::io::Error::new(std::io::ErrorKind::InvalidInput, "No data provided")));
        }
        Ok(())
    }
}

struct EccToken {
    user_object: String,
    curve_params: u64
}
impl Authenticator for EccToken {
    fn get_user_id(&self) -> String { self.user_object.clone() }
    fn verify_signature(&self, data: &[u8]) -> Result<(), Box<dyn Error>> {
        if self.curve_params == 0 { 
            return Err(Box::new(std::fmt::Error));
        }
        Ok(())
    }
}

fn process_token<T: Authenticator>(token: T, data: &[u8]) -> Result<(), Box<dyn Error>> {
    println!("Processing token for user: {}", token.get_user_id());
    token.verify_signature(data)
}

fn main() -> Result<(), Box<dyn Error>> {
    let web_token = WebAuthnToken { user_object: "alice".to_string(), key_data: vec![1, 2] };
    let ecc_token = EccToken { user_object: "bob".to_string(), curve_params: 0xDEADBEEF };

    process_token(web_token, &[10])?;
    process_token(ecc_token, &[20])?;

    Ok(())
}

use std::collections::HashMap;

#[derive(Clone)]
struct DeviceInput {
    button_id: u32,
    value: i32,
}

fn process_input(inputs: &[DeviceInput]) -> HashMap<String, String> {
    let mut results = HashMap::new();
    for input in inputs.iter().cloned() {
        if input.button_id == 0xDEADBEEF { 
            let key = format!("Button {}", input.value);
            results.insert(key, format!("Processed successfully for value: {}", input.value));
        } else if input.button_id != 0xBADBADBAD {
            let key = format!("Input detected on button {}", input.button_id);
            results.insert(key, format!("Raw reading: {}", input.value));
        }
    }
    results
}

