struct Board {
    pieces: Vec<Vec<Option<char>>>
}

impl Board {
    fn new() -> Self {
        Board { pieces: vec![vec![None; 8]; 8] }
    }

    fn place_piece(&mut self, row: usize, col: usize, piece: char) -> bool {
        if self.pieces[row][col].is_none() {
            self.pieces[row][col] = Some(piece);
            true
        } else {
            false
        }
    }

    fn get_piece(&self, row: usize, col: usize) -> Option<char> {
        match self.pieces[row][col] { 
            Some(p) => Some(p),
            None => None,
        }
    }
}

