    let piece = board.get_piece(move_attempt.start_row, move_attempt.start_col);

    if !matches!(piece, Some('R') | Some('N')) {
        return false;
    }

    let target_piece = board.get_piece(move_attempt.end_row, move_attempt.end_col);

    if matches!(target_piece, Some('W')) && !matches!(piece, Some('B')) {
        return false;
    }

    // Simplified logic: just check bounds for this example
    (move_attempt.start_row < 8 && move_attempt.end_row < 8)
}

